cat > /tmp/test_overflow.cpp << 'EOF'
#include <cstdio>
#include <cstdint>

int main() {
    uint32_t count = 70'000'000u;
    uint32_t size = 64u;
    uint32_t bytes = count * size;

    printf("count = %u\n", count);
    printf("size = %u\n", size);
    printf("count * size (uint32_t) = %u\n", bytes);
    printf("count * size (uint64_t) = %llu\n", (uint64_t)count * size);

    return 0;
}
EOF
g++ -o /tmp/test_overflow /tmp/test_overflow.cpp && /tmp/test_overflow
